export interface CandidateEvaluation {
  id: number;
  runId: number;
  jobId: number;
  candidateId: number;
  /** Decision score (backward-compat alias). Use decisionScore. */
  score: number;
  /** AI-assessed candidate fit (0-100). Not penalized by data quality. */
  fitScore?: number | null;
  /** How complete and verifiable the candidate's profile is (0-100). */
  dataConfidenceScore?: number | null;
  /** fitScore × (0.6 + 0.4 × dataConfidence/100). Main ranking score. */
  decisionScore?: number | null;
  confidenceLevel?: ConfidenceLevel | null;
  confidenceReason?: string | null;
  missingDataWarnings?: string[];
  /** True when data confidence was too low and no enrichment provider was available. Score reliability is reduced — enrichment is recommended before acting on this result. */
  requiresEnrichment?: boolean | null;
  strengths: string[];
  gaps: string[];
  risks: string[];
  recommendation: Recommendation;
  candidate: Candidate;
  createdAt: string;
}

