export type TelemetryDashboardRange =
  (typeof TelemetryDashboardRange)[keyof typeof TelemetryDashboardRange];

export const TelemetryDashboardRange = {
  "7d": "7d",
  "30d": "30d",
} as const;

/**
 * Echo of the filters that were actually applied.
 */
export type TelemetryDashboardFilters = {
  provider: string | null;
  workflowStep: string | null;
};

/**
 * Distinct filter values discovered in the same time range, so the
UI can populate the Provider and Workflow Step dropdowns from the
data instead of hard-coding them.

 */
export type TelemetryDashboardAvailableFilters = {
  providers: string[];
  workflowSteps: string[];
};

export interface TelemetryDailyCount {
  /** ISO date (YYYY-MM-DD) in UTC. */
  date: string;
  count: number;
}

export interface TelemetryEventStats {
  event: string;
  total: number;
  daily: TelemetryDailyCount[];
}

/**
 * Aggregate counts for the five allow-listed telemetry events. When the
server has no PostHog credentials configured, `configured` is false
and `events` is empty.

 */
export interface TelemetryDashboard {
  configured: boolean;
  range: TelemetryDashboardRange;
  events: TelemetryEventStats[];
  /** Echo of the filters that were actually applied. */
  filters: TelemetryDashboardFilters;
  /** Distinct filter values discovered in the same time range, so the
UI can populate the Provider and Workflow Step dropdowns from the
data instead of hard-coding them.
 */
  availableFilters: TelemetryDashboardAvailableFilters;
}

